import { graphql, useStaticQuery } from "gatsby";
import type { Post } from "@/lib/types/post";

const useSpacePosts = () => {
  const data = useStaticQuery(graphql`
    query spacePosts {
      space: allMdx(
        filter: { internal: { contentFilePath: { regex: "/posts/space/" } } }
        sort: { frontmatter: { date: DESC } }
      ) {
        edges {
          node {
            fields {
              timeToRead {
                minutes
                text
                time
                words
              }
            }
            frontmatter {
              title
              description
              date
            }
            internal {
              contentFilePath
            }
          }
        }
      }
    }
  `);
  return data.space.edges as Post[];
};

export { useSpacePosts };
